import { provide, reactive, readonly, computed, InjectionKey } from 'vue'

export interface ThemeContext {
  isDark: boolean
  primaryColor: string
  accentColor: string
  toggleTheme: () => void
  setPrimaryColor: (color: string) => void
}

const THEME_KEY: InjectionKey<ThemeContext> = Symbol('theme')

export function useThemeProvider() {
  const state = reactive({
    isDark: false,
    primaryColor: '#3b82f6',
    accentColor: '#10b981'
  })

  const theme: ThemeContext = {
    get isDark() { return state.isDark },
    get primaryColor() { return state.primaryColor },
    get accentColor() { return state.accentColor },
    toggleTheme() { state.isDark = !state.isDark },
    setPrimaryColor(color: string) { state.primaryColor = color }
  }

  provide(THEME_KEY, theme)

  return {
    theme: readonly(theme),
    injectTheme: () => inject(THEME_KEY)
  }
}

export function useTheme() {
  const theme = inject(THEME_KEY)
  if (!theme) {
    throw new Error('useTheme must be used within a ThemeProvider')
  }
  return theme
}

// App.vue usage:
// <script setup>
// import { useThemeProvider } from './plugins/theme-provider'
// const { theme } = useThemeProvider()
// </script>
//
// <template>
//   <div :class="{ 'dark-theme': theme.isDark }">
//     <button @click="theme.toggleTheme">Toggle Theme</button>
//   </div>
// </template>

import { ref, watch, onUnmounted, computed } from 'vue'

export function useDebounce<T>(source: Ref<T>, delay = 300): ComputedRef<T> {
  const debouncedValue = ref(source.value) as Ref<T>
  let timeoutId: ReturnType<typeof setTimeout> | null = null

  watch(source, (newValue) => {
    if (timeoutId !== null) {
      clearTimeout(timeoutId)
    }
    timeoutId = setTimeout(() => {
      debouncedValue.value = newValue
      timeoutId = null
    }, delay)
  }, { immediate: true })

  onUnmounted(() => {
    if (timeoutId !== null) {
      clearTimeout(timeoutId)
    }
  })

  return debouncedValue
}

export function useSearch(initialQuery = '') {
  const query = ref(initialQuery)
  const results = ref([])
  const isLoading = ref(false)
  const error = ref(null)

  const debouncedQuery = useDebounce(query, 300)

  async function performSearch() {
    isLoading.value = true
    error.value = null
    try {
      const response = await fetch(`/api/search?q=${debouncedQuery.value}`)
      if (!response.ok) throw new Error('Search failed')
      results.value = await response.json()
    } catch (e) {
      error.value = e.message
    } finally {
      isLoading.value = false
    }
  }

  watch(debouncedQuery, performSearch, { immediate: true })

  return { query, results, isLoading, error }
}

// Usage in component:
// <script setup>
// import { useSearch } from '@/composables/useSearch'
// const { query, results, isLoading, error } = useSearch()
// </script>

import { ref, computed, watch, shallowRef } from 'vue'

export function useFilter(data, filters, transform = null) {
  const searchQuery = ref('')
  const activeFilters = shallowRef({})
  const sortBy = ref('createdAt')
  const sortOrder = ref('asc')
  const page = ref(1)
  const pageSize = ref(10)

  const filteredData = computed(() => {
    let result = [...data]

    // Text search
    if (searchQuery.value) {
      const query = searchQuery.value.toLowerCase()
      result = result.filter(item =>
        Object.values(item).some(val =>
          String(val).toLowerCase().includes(query)
        )
      )
    }

    // Active filters
    Object.entries(activeFilters.value).forEach(([key, value]) => {
      if (value) {
        result = result.filter(item => item[key] === value)
      }
    })

    // Sort
    result.sort((a, b) => {
      const aVal = a[sortBy.value]
      const bVal = b[sortBy.value]
      return sortOrder.value === 'desc' ? bVal - aVal : aVal - bVal
    })

    // Transform
    if (transform) {
      result = transform(result)
    }

    return result
  })

  const paginatedData = computed(() => {
    const start = (page.value - 1) * pageSize.value
    return filteredData.value.slice(start, start + pageSize.value)
  })

  const totalPages = computed(() =>
    Math.ceil(filteredData.value.length / pageSize.value)
  )

  watch([searchQuery, activeFilters, sortBy, sortOrder], () => {
    page.value = 1
  })

  return {
    searchQuery,
    activeFilters,
    sortBy,
    sortOrder,
    page,
    pageSize,
    filteredData,
    paginatedData,
    totalPages,
    setFilter: (key, value) => { activeFilters.value[key] = value },
    clearFilters: () => { activeFilters.value = {} }
  }
}

import { DirectiveBinding, Directive } from 'vue'

interface TooltipOptions {
  text: string
  position: 'top' | 'bottom' | 'left' | 'right'
  delay: number
  theme: 'light' | 'dark'
}

function createTooltipElement(options: TooltipOptions): HTMLElement {
  const tooltip = document.createElement('div')
  tooltip.className = `tooltip tooltip-${options.position} tooltip-${options.theme}`
  tooltip.textContent = options.text
  tooltip.style.position = 'fixed'
  tooltip.style.pointerEvents = 'none'
  tooltip.style.zIndex = '9999'
  tooltip.style.opacity = '0'
  tooltip.style.transition = 'opacity 0.2s ease'
  document.body.appendChild(tooltip)
  return tooltip
}

export const vTooltip: Directive = {
  mounted(el: HTMLElement, binding: DirectiveBinding) {
    const options: TooltipOptions = {
      text: binding.value?.text || binding.arg || '',
      position: binding.value?.position || 'top',
      delay: binding.value?.delay || 200,
      theme: binding.value?.theme || 'dark'
    }

    let timeoutId: ReturnType<typeof setTimeout>
    let tooltip: HTMLElement

    el.addEventListener('mouseenter', () => {
      timeoutId = setTimeout(() => {
        tooltip = createTooltipElement(options)
        const rect = el.getBoundingClientRect()
        tooltip.style.left = `${rect.left + rect.width / 2}px`
        tooltip.style.top = `${rect.top - 30}px`
        requestAnimationFrame(() => {
          tooltip.style.opacity = '1'
        })
      }, options.delay)
    })

    el.addEventListener('mouseleave', () => {
      clearTimeout(timeoutId)
      if (tooltip) {
        tooltip.style.opacity = '0'
        setTimeout(() => tooltip.remove(), 200)
      }
    })

    el._tooltip = tooltip
  },

  unmounted(el: HTMLElement) {
    if (el._tooltip) {
      el._tooltip.remove()
    }
    el.removeEventListener('mouseenter', null)
    el.removeEventListener('mouseleave', null)
  }
}

// Usage:
// <button v-tooltip="{ text: 'Click to save', position: 'top', delay: 100 }">Save</button>
// <span v-tooltip:bottom="'Default tooltip'">Hover me</span>

import { App, reactive, computed, inject } from 'vue'

interface TranslationMessage {
  [key: string]: string | TranslationMessage
}

interface I18nOptions {
  locale: string
  fallbackLocale: string
  messages: Record<string, TranslationMessage>
}

class I18nPlugin {
  private app: App | null = null
  private state: {
    locale: string
    fallbackLocale: string
    messages: Record<string, TranslationMessage>
  }

  constructor(options: I18nOptions) {
    this.state = reactive({
      locale: options.locale,
      fallbackLocale: options.fallbackLocale,
      messages: options.messages
    })
  }

  install(app: App) {
    this.app = app

    const i18n = {
      t(key: string, params?: Record<string, string>): string {
        const message = resolveMessage(this.state.messages, this.state.locale, key)
        const fallback = resolveMessage(this.state.messages, this.state.fallbackLocale, key)
        return formatMessage(message || fallback || key, params)
      },
      setLocale(locale: string) { this.state.locale = locale },
      getLocale(): string { return this.state.locale }
    }

    app.provide('i18n', i18n)
    app.config.globalProperties.$t = i18n.t.bind(i18n)
    app.config.globalProperties.$i18n = i18n
  }
}

function resolveMessage(messages: Record<string, TranslationMessage>, locale: string, key: string): string | undefined {
  const localeMessages = messages[locale] || messages[messages.fallbackLocale]
  const parts = key.split('.')
  let current: any = localeMessages

  for (const part of parts) {
    if (current && typeof current === 'object' && part in current) {
      current = current[part]
    } else {
      return undefined
    }
  }

  return typeof current === 'string' ? current : undefined
}

function formatMessage(template: string, params?: Record<string, string>): string {
  if (!params) return template
  return template.replace(/\{(\w+)\}/g, (_, key) => params[key] || `{${key}}`)
}

export function useI18n() {
  const i18n = inject('i18n')
  if (!i18n) throw new Error('useI18n must be used after installing I18nPlugin')
  return i18n
}

export default I18nPlugin
